function parseNumericValue(value: string) {
  const normalized = value.replace(/,/g, "").replace(/\u2212/g, "-");
  const parentheses = normalized.match(/\((\d+(\.\d+)?)\)/);
  if (parentheses) return -Number(parentheses[1]);
  const match = normalized.match(/-?\d+(\.\d+)?/);
  return match ? Number(match[0]) : null;
}

function shortChartLabel(label: string) {
  const cleaned = label
    .replace(/\([^)]*\)/g, "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\bmonthly\b/gi, "Mo.")
    .replace(/\bannual\b/gi, "Ann.")
    .replace(/\bpercentage\b/gi, "%");
  return cleaned.length > 20 ? `${cleaned.slice(0, 18).trim()}...` : cleaned;
}

function dedupeChartPoints(points: ChartPoint[]) {
  const seen = new Set<string>();
  return points.filter((point) => {
    if (!Number.isFinite(point.value)) return false;
    const key = `${point.label.toLowerCase()}:${point.value}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function getSnapshotNumbers(snapshot: Omit<HistoryItem, "id" | "timestamp"> | null) {
  if (!snapshot) return { inputs: [], results: [] };
  const inputs = dedupeChartPoints(snapshot.inputs
    .map((input) => {
      const [rawLabel, ...rest] = input.split(":");
      const label = shortChartLabel(rawLabel);
      const value = parseNumericValue(rest.join(":"));
      return value === null ? null : { label, value };
    })
    .filter((item): item is ChartPoint => Boolean(item)));

  const results = dedupeChartPoints(snapshot.result
    .split("|")
    .map((result, index) => {
      const [maybeLabel, ...rest] = result.split(":");
      const hasLabel = rest.length > 0;
      const label = shortChartLabel(hasLabel ? maybeLabel : `Result ${index + 1}`);
      const value = parseNumericValue(result);
      return value === null ? null : { label, value };
    })
    .filter((item): item is ChartPoint => Boolean(item)));

  return { inputs, results };
}

function getChartKind(inputs: ChartPoint[]) {
  if (typeof window === "undefined") return "bar";
  const path = window.location.pathname;
  if (path.includes("budget")) return "pie";
  if (
    inputs.some((item) => /amount|balance|price|principal|loan|mortgage|debt/i.test(item.label)) &&
    (path.includes("loan") || path.includes("mortgage") || path.includes("amortization") || path.includes("debt") || path.includes("repayment") || path.includes("payoff"))
  ) return "line";
  return "bar";
}

function getLineChartData(inputs: ChartPoint[]) {
  const amount =
    inputs.find((item) => /loan amount|mortgage amount|balance|principal|debt balance/i.test(item.label))?.value ||
    inputs.find((item) => /home price|vehicle price|price|amount/i.test(item.label))?.value ||
    inputs[0]?.value ||
    10000;
  const rate = inputs.find((item) => /rate|apr|interest/i.test(item.label))?.value || 6;
  const termPoint = inputs.find((item) => /term|year|month|period|payments/i.test(item.label));
  const rawTerm = termPoint?.value || 5;
  const years = /month|payments/i.test(termPoint?.label || "") ? rawTerm / 12 : rawTerm;
  const totalMonths = Math.max(12, Math.min(360, Math.round(years * 12)));
  const monthlyRate = rate / 100 / 12;
  const payment = monthlyRate > 0
    ? amount * (monthlyRate * Math.pow(1 + monthlyRate, totalMonths)) / (Math.pow(1 + monthlyRate, totalMonths) - 1)
    : amount / totalMonths;
  const stepMonths = Math.max(1, Math.ceil(totalMonths / 10));
  const data = [{ label: "Start", balance: Math.round(amount), principal: 0 }];
  let balance = amount;

  for (let month = 1; month <= totalMonths; month += 1) {
    const interest = balance * monthlyRate;
    const principal = Math.min(balance, payment - interest);
    balance = Math.max(0, balance - principal);
    if (month % stepMonths === 0 || month === totalMonths) {
      data.push({
        label: totalMonths <= 24 ? `Mo. ${month}` : `Yr ${Math.round(month / 12)}`,
        balance: Math.round(balance),
        principal: Math.round(amount - balance),
      });
    }
  }

  return data.filter((point, index, list) => index === 0 || point.label !== list[index - 1].label);
}

function getPieChartData(inputs: ChartPoint[], results: ChartPoint[]) {
  const path = typeof window === "undefined" ? "" : window.location.pathname;
  const source = path.includes("budget")
    ? inputs.filter((item) => !/income|rate|remaining|total|balance/i.test(item.label))
    : (results.length > 1 ? results : inputs);

  return source
    .filter((item) => item.value > 0)
    .slice(0, 8)
    .map((item) => ({ ...item, value: Math.abs(item.value) }));
}

function getBarChartData(inputs: ChartPoint[], results: ChartPoint[]) {
  const source = results.length > 0 ? results : inputs;
  return source
    .filter((item) => Number.isFinite(item.value))
    .slice(0, 8)
    .map((item) => ({ ...item, value: Math.abs(item.value) }));
}

function getVisualKind(baseKind: string) {
  if (typeof window === "undefined") return baseKind;
  const path = window.location.pathname;
  if (baseKind === "line" || baseKind === "pie") return baseKind;
  if (/atom|mole|molecular|electron|oxidation|ph-|titration|stoichiometry|gas|dilution|buffer|yield|formula|charles|boyles/.test(path)) return "molecular";
  if (/newtons|kinetic|potential|work-and-power|wavelength|frequency|pressure|torque|acceleration|force|momentum|electric-field|capacitance/.test(path)) return "physics";
  if (/bmi|bmr|calorie|body|weight|macro|protein|carbohydrate|fat|tdee|heart|pregnancy|ovulation|period|gfr|bac/.test(path)) return "gauge";
  if (/youtube|instagram|tiktok|social|influencer|subscriber|channel|traffic|ctr|pricing/.test(path)) return "signal";
  if (/scientific|fraction|percentage|standard-deviation|random|password|converter|subnet|base64|url|roman|calculator$/.test(path)) return "matrix";
  return baseKind;
}

