async function copyText(text: string) {
  try {
    await navigator.clipboard.writeText(text);
  } catch {
    const input = document.createElement("textarea");
    input.value = text;
    input.setAttribute("readonly", "");
    input.style.position = "fixed";
    input.style.opacity = "0";
    document.body.appendChild(input);
    input.select();
    document.execCommand("copy");
    document.body.removeChild(input);
  }
}

function escapeHtml(value: string) {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function printCalculation(snapshot: Omit<HistoryItem, "id" | "timestamp">) {
  const title = getPageTitle();
  const frame = document.createElement("iframe");
  frame.setAttribute("aria-hidden", "true");
  frame.style.position = "fixed";
  frame.style.right = "0";
  frame.style.bottom = "0";
  frame.style.width = "0";
  frame.style.height = "0";
  frame.style.border = "0";
  document.body.appendChild(frame);

  const doc = frame.contentWindow?.document;
  if (!doc) {
    document.body.removeChild(frame);
    return;
  }

  doc.open();
  doc.write(`
    <!doctype html>
    <html>
      <head>
        <title>${escapeHtml(title)}</title>
        <style>
          * { box-sizing: border-box; }
          body { margin: 0; padding: 32px; color: #111827; font-family: Arial, sans-serif; line-height: 1.5; }
          .sheet { max-width: 720px; margin: 0 auto; }
          h1 { margin: 0 0 20px; font-size: 28px; line-height: 1.2; }
          h2 { margin: 24px 0 10px; font-size: 14px; color: #4f46e5; text-transform: uppercase; letter-spacing: .08em; }
          ul { margin: 0; padding: 0; list-style: none; }
          li { padding: 8px 0; border-bottom: 1px solid #e5e7eb; }
          .result { margin-top: 8px; padding: 16px; border: 1px solid #d1d5db; border-radius: 12px; font-size: 20px; font-weight: 700; }
          .meta { margin-top: 24px; color: #6b7280; font-size: 12px; }
        </style>
      </head>
      <body>
        <main class="sheet">
          <h1>${escapeHtml(title)}</h1>
          <h2>Inputs</h2>
          <ul>${snapshot.inputs.map((input) => `<li>${escapeHtml(input)}</li>`).join("")}</ul>
          <h2>Result</h2>
          <div class="result">${escapeHtml(snapshot.result)}</div>
          ${snapshot.notes ? `<h2>Notes</h2><p>${escapeHtml(snapshot.notes)}</p>` : ""}
          <p class="meta">Printed from CalcHive</p>
        </main>
      </body>
    </html>
  `);
  doc.close();

  window.setTimeout(() => {
    frame.contentWindow?.focus();
    frame.contentWindow?.print();
    window.setTimeout(() => document.body.removeChild(frame), 1000);
  }, 100);
}

export default function ShareButton() {
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const [resultCopied, setResultCopied] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [notes, setNotes] = useState("");
  const [notesStatus, setNotesStatus] = useState<NotesStatus>("idle");
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [historyCleared, setHistoryCleared] = useState(false);
  const [selectedHistoryIds, setSelectedHistoryIds] = useState<string[]>([]);
  const [editingHistoryId, setEditingHistoryId] = useState<string | null>(null);
  const [editingInputs, setEditingInputs] = useState("");
  const [editingResult, setEditingResult] = useState("");
  const [editingNotes, setEditingNotes] = useState("");
  const ref = useRef<HTMLDivElement>(null);
  const lastSnapshotRef = useRef("");
  const saveTimerRef = useRef<number | undefined>(undefined);
  const notesFeedbackTimerRef = useRef<number | undefined>(undefined);
  const clearedSignatureRef = useRef("");
  const clearFeedbackTimerRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    if (!open) return;
    const onPointerDown = (event: PointerEvent) => {
      if (!ref.current?.contains(event.target as Node)) setOpen(false);
    };
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") setOpen(false);
    };
    document.addEventListener("pointerdown", onPointerDown);
    document.addEventListener("keydown", onKeyDown);
    return () => {
      document.removeEventListener("pointerdown", onPointerDown);
      document.removeEventListener("keydown", onKeyDown);
    };
  }, [open]);

  useEffect(() => {
    setHistory(loadHistory());
    const storedNotes = loadNotes();
    setNotes(storedNotes);
    if (storedNotes) {
      setNotesStatus("restored");
      notesFeedbackTimerRef.current = window.setTimeout(() => setNotesStatus("idle"), 1800);
    }
    applySharedCalculationFromUrl();
  }, []);

  useEffect(() => {
    const addSnapshot = () => {
      window.clearTimeout(saveTimerRef.current);
      saveTimerRef.current = window.setTimeout(() => {
        const snapshot = collectCalculationSnapshot(notes);
        if (!snapshot) return;

        const signature = historySignature(snapshot);
        if (signature === clearedSignatureRef.current) return;
        if (signature === lastSnapshotRef.current) return;
        lastSnapshotRef.current = signature;

        setHistory((current) => {
          const next = [
            {
              id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
              timestamp: Date.now(),
              ...snapshot,
            },
            ...current.filter((item) => historySignature(item) !== signature),
          ].slice(0, 5);
          saveHistory(next);
          return next;
        });
      }, 650);
    };

    const onInput = (event: Event) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement || target instanceof HTMLSelectElement || target instanceof HTMLTextAreaElement)) return;
      if (target.closest("[data-calculation-history-root], nav, header, footer, [data-chatbot], [data-newsletter]")) return;
      clearedSignatureRef.current = "";
      setHistoryCleared(false);
      addSnapshot();
    };

    const onClick = (event: MouseEvent) => {
      const target = event.target as HTMLElement | null;
      const button = target?.closest("button");
      if (!button || button.closest("[data-calculation-history-root], nav, header, footer, [data-chatbot], [data-newsletter]")) return;
      addSnapshot();
    };

    document.addEventListener("input", onInput);
    document.addEventListener("change", onInput);
    document.addEventListener("click", onClick);
    return () => {
      window.clearTimeout(saveTimerRef.current);
      document.removeEventListener("input", onInput);
      document.removeEventListener("change", onInput);
      document.removeEventListener("click", onClick);
    };
  }, [notes]);

  useEffect(() => {
    return () => {
      window.clearTimeout(saveTimerRef.current);
      window.clearTimeout(clearFeedbackTimerRef.current);
      window.clearTimeout(notesFeedbackTimerRef.current);
    };
  }, []);

  const currentSnapshot = collectCalculationSnapshot(notes);
  const explanation = buildCalculationExplanation(currentSnapshot);
  const notesStatusText: Record<NotesStatus, string> = {
    idle: notes ? "Draft note ready. Click Done to save it on this device." : "Add private notes for this calculator on this device.",
    restored: "Restored your saved note for this calculator.",
    saving: "Saving note...",
    saved: "Note saved.",
    cleared: "Note cleared.",
    error: "Could not save note in this browser.",
  };

  const updateNotes = (value: string) => {
    setNotes(value);
    window.clearTimeout(notesFeedbackTimerRef.current);
    setNotesStatus("idle");
  };

  const saveCurrentNote = () => {
    window.clearTimeout(notesFeedbackTimerRef.current);
    setNotesStatus("saving");
    const saved = saveNotes(notes);
    notesFeedbackTimerRef.current = window.setTimeout(() => {
      setNotesStatus(saved ? (notes.trim() ? "saved" : "cleared") : "error");
      notesFeedbackTimerRef.current = window.setTimeout(() => setNotesStatus("idle"), 1800);
    }, 220);
  };

  const clearNotes = () => {
    setNotes("");
    window.clearTimeout(notesFeedbackTimerRef.current);
    const saved = saveNotes("");
    setNotesStatus(saved ? "cleared" : "error");
    notesFeedbackTimerRef.current = window.setTimeout(() => setNotesStatus("idle"), 1800);
  };

  const clearHistory = () => {
    window.clearTimeout(saveTimerRef.current);
    const snapshot = collectCalculationSnapshot(notes);
    clearedSignatureRef.current = snapshot ? historySignature(snapshot) : "";
    saveHistory([]);
    setHistory([]);
    setSelectedHistoryIds([]);
    lastSnapshotRef.current = clearedSignatureRef.current;
    setHistoryCleared(true);
    window.clearTimeout(clearFeedbackTimerRef.current);
    clearFeedbackTimerRef.current = window.setTimeout(() => setHistoryCleared(false), 2600);
  };

  const deleteHistoryItem = (id: string) => {
    setHistory((current) => {
      const next = current.filter((item) => item.id !== id);
      saveHistory(next);
      if (next.length === 0) {
        setHistoryCleared(true);
        window.clearTimeout(clearFeedbackTimerRef.current);
        clearFeedbackTimerRef.current = window.setTimeout(() => setHistoryCleared(false), 2200);
      }
      return next;
    });
    setSelectedHistoryIds((current) => current.filter((itemId) => itemId !== id));
    if (editingHistoryId === id) setEditingHistoryId(null);
  };

  const toggleHistorySelection = (id: string) => {
    setSelectedHistoryIds((current) =>
      current.includes(id) ? current.filter((itemId) => itemId !== id) : [...current, id],
    );
  };

  const deleteSelectedHistory = () => {
    if (selectedHistoryIds.length === 0) return;
    const selected = new Set(selectedHistoryIds);
    setHistory((current) => {
      const next = current.filter((item) => !selected.has(item.id));
      saveHistory(next);
      if (next.length === 0) {
        setHistoryCleared(true);
        window.clearTimeout(clearFeedbackTimerRef.current);
        clearFeedbackTimerRef.current = window.setTimeout(() => setHistoryCleared(false), 2200);
      }
      return next;
    });
    setSelectedHistoryIds([]);
  };

  const toggleAllHistorySelection = () => {
    setSelectedHistoryIds((current) =>
      current.length === history.length ? [] : history.map((item) => item.id),
    );
  };

  const startEditingHistory = (item: HistoryItem) => {
    setEditingHistoryId(item.id);
    setEditingInputs(item.inputs.join("\n"));
    setEditingResult(item.result);
    setEditingNotes(item.notes || "");
  };

  const cancelEditingHistory = () => {
    setEditingHistoryId(null);
    setEditingInputs("");
    setEditingResult("");
    setEditingNotes("");
  };

  const saveEditingHistory = () => {
    if (!editingHistoryId) return;
    const inputs = editingInputs
      .split(/\n+/)
      .map((input) => input.trim())
      .filter(Boolean);
    const result = editingResult.trim();
    setHistory((current) => {
      const next = current.map((item) =>
        item.id === editingHistoryId
          ? {
              ...item,
              inputs: inputs.length ? inputs : item.inputs,
              result: result || item.result,
              notes: editingNotes.trim() || undefined,
            }
          : item,
      );
      saveHistory(next);
      return next;
    });
    cancelEditingHistory();
  };

  const removeHistoryNote = (id: string) => {
    setHistory((current) => {
      const next = current.map((item) => item.id === id ? { ...item, notes: undefined } : item);
      saveHistory(next);
      return next;
    });
    if (editingHistoryId === id) setEditingNotes("");
  };

  const copyLink = async () => {
    const snapshot = collectCalculationSnapshot(notes);
    const { url } = getShareData(snapshot);
    await copyText(url);
    setCopied(true);
    window.setTimeout(() => setCopied(false), 1800);
  };

  const copyResult = async () => {
    const snapshot = collectCalculationSnapshot(notes);
    if (!snapshot) return;
    await copyText(buildCalculationSummary(snapshot));
    setResultCopied(true);
    window.setTimeout(() => setResultCopied(false), 1800);
  };

  const printResult = () => {
    const snapshot = collectCalculationSnapshot(notes);
    if (!snapshot) return;
    printCalculation(snapshot);
  };

  const shareTo = (target: "twitter" | "whatsapp") => {
    const snapshot = collectCalculationSnapshot(notes);
    const { text, url } = getShareData(snapshot);
    const href =
      target === "twitter"
        ? `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}&url=${encodeURIComponent(url)}`
        : `https://wa.me/?text=${encodeURIComponent(`${text} ${url}`)}`;
    window.open(href, "_blank", "noopener,noreferrer");
    setOpen(false);
  };

  return (
    <div data-calculation-history-root className="mb-8 space-y-4">
      <div className="flex flex-wrap items-center justify-center gap-2.5">
        <button
          type="button"
          onClick={printResult}
          className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm transition-colors hover:border-primary/40 hover:bg-accent focus:outline-none focus:ring-2 focus:ring-primary/30"
        >
          <Printer className="h-4 w-4 text-primary" />
          Print Result
        </button>
        <button
          type="button"
          onClick={copyResult}
          className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm transition-colors hover:border-primary/40 hover:bg-accent focus:outline-none focus:ring-2 focus:ring-primary/30"
          aria-live="polite"
        >
          {resultCopied ? <Check className="h-4 w-4 text-emerald-500" /> : <Copy className="h-4 w-4 text-primary" />}
          {resultCopied ? "Copied!" : "Copy Result"}
        </button>
        <button
          type="button"
          onClick={() => setShowExplanation((value) => !value)}
          className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm transition-colors hover:border-primary/40 hover:bg-accent focus:outline-none focus:ring-2 focus:ring-primary/30"
          aria-expanded={showExplanation}
        >
          <BookOpenText className="h-4 w-4 text-primary" />
          Show me how this was calculated
        </button>
        <div ref={ref} className="relative">
          <button
            type="button"
            onClick={() => setOpen((value) => !value)}
            className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm transition-colors hover:border-primary/40 hover:bg-accent focus:outline-none focus:ring-2 focus:ring-primary/30"
            aria-expanded={open}
            aria-haspopup="menu"
          >
            <Share2 className="h-4 w-4 text-primary" />
            Share Result
          </button>

          {open && (
            <>
              <div className="fixed inset-0 z-40 bg-background/50 backdrop-blur-sm sm:hidden" />
              <div
                role="menu"
                className="fixed inset-x-3 bottom-4 z-50 overflow-hidden rounded-2xl border border-border bg-card p-2 shadow-2xl sm:left-auto sm:right-6 sm:w-80"
              >
                <div className="flex items-center justify-between px-3 py-2">
                  <div>
                    <p className="text-sm font-bold text-foreground">Share this result</p>
                    <p className="text-xs text-muted-foreground">Copy a unique link that reopens these exact inputs.</p>
                  </div>
                  <button
                    type="button"
                    onClick={() => setOpen(false)}
                    className="flex h-8 w-8 items-center justify-center rounded-full text-muted-foreground transition-colors hover:bg-accent hover:text-foreground"
                    aria-label="Close share menu"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>

                <div className="space-y-1">
                  <button
                    type="button"
                    role="menuitem"
                    onClick={copyLink}
                    className="flex w-full items-center gap-3 rounded-xl px-3 py-3 text-left text-sm font-semibold text-foreground transition-colors hover:bg-accent"
                  >
                    <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-primary/10">
                      {copied ? <Check className="h-4 w-4 text-emerald-500" /> : <Copy className="h-4 w-4 text-primary" />}
                    </span>
                    {copied ? "Copied!" : "Copy Calculation Link"}
                  </button>
                  <button
                    type="button"
                    role="menuitem"
                    onClick={() => shareTo("twitter")}
                    className="flex w-full items-center gap-3 rounded-xl px-3 py-3 text-left text-sm font-semibold text-foreground transition-colors hover:bg-accent"
                  >
                    <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-foreground/10">
                      <X className="h-4 w-4 text-foreground" />
                    </span>
                    Share on Twitter/X
                  </button>
                  <button
                    type="button"
                    role="menuitem"
                    onClick={() => shareTo("whatsapp")}
                    className="flex w-full items-center gap-3 rounded-xl px-3 py-3 text-left text-sm font-semibold text-foreground transition-colors hover:bg-accent"
                  >
                    <span className="flex h-9 w-9 items-center justify-center rounded-xl bg-emerald-500/10">
                      <MessageCircle className="h-4 w-4 text-emerald-500" />
                    </span>
                    Share on WhatsApp
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {showExplanation && (
        <section className="rounded-2xl border border-indigo-200/80 bg-indigo-50/60 p-4 shadow-sm dark:border-indigo-800/50 dark:bg-indigo-950/20" aria-labelledby="calculation-explanation-heading">
          <h2 id="calculation-explanation-heading" className="mb-3 flex items-center gap-2 text-sm font-bold text-indigo-700 dark:text-indigo-300">
            <BookOpenText className="h-4 w-4" />
            How this was calculated
          </h2>
          <div className="rounded-xl border border-indigo-100 bg-white/70 p-3 font-mono text-xs leading-relaxed text-foreground dark:border-indigo-900/60 dark:bg-white/[0.04]">
            {explanation.formula}
          </div>
          <div className="mt-3 space-y-2 text-sm leading-relaxed text-muted-foreground">
            {explanation.steps.map((step, index) => (
              <p key={step}>
                <span className="font-bold text-foreground">Step {index + 1}:</span> {step}
              </p>
            ))}
          </div>
        </section>
      )}

      <ProgressIndicator snapshot={currentSnapshot} />
      <Suspense fallback={null}>
        <CalculatorVisualInsight snapshot={currentSnapshot} />
      </Suspense>
      <Suspense fallback={null}>
        <CalculatorChaining />
      </Suspense>

      <section
        className={`rounded-2xl border border-border bg-card p-4 shadow-sm transition-all duration-200 ${
          notesStatus === "saved" || notesStatus === "restored" ? "scale-[1.006] shadow-lg shadow-primary/10" : ""
        }`}
        aria-labelledby="calculation-notes-heading"
      >
        <div className="mb-2 flex items-center justify-between gap-3">
          <label id="calculation-notes-heading" htmlFor="calculation-notes" className="flex items-center gap-2 text-sm font-bold text-foreground">
            <span
              className={`flex h-8 w-8 items-center justify-center rounded-xl bg-primary/10 transition-transform duration-200 ${
                notesStatus === "saving" ? "scale-95" : notesStatus === "saved" || notesStatus === "restored" ? "rotate-3 scale-105" : ""
              }`}
            >
              <StickyNote className="h-4 w-4 text-primary" />
            </span>
            Calculator Notes
          </label>
          <div className="flex items-center gap-2">
            {notes && (
              <button
                type="button"
                onClick={clearNotes}
                className="rounded-full border border-border px-3 py-1.5 text-xs font-semibold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
              >
                Clear note
              </button>
            )}
            <button
              type="button"
              onClick={saveCurrentNote}
              disabled={!notes.trim()}
              className="inline-flex items-center gap-1.5 rounded-full bg-primary px-3 py-1.5 text-xs font-bold text-primary-foreground shadow-sm shadow-primary/20 transition-all duration-200 hover:-translate-y-0.5 hover:shadow-md hover:shadow-primary/25 active:translate-y-0 disabled:cursor-not-allowed disabled:opacity-45 disabled:hover:translate-y-0 focus:outline-none focus:ring-2 focus:ring-primary/30"
            >
              {notesStatus === "saved" ? <Check className="h-3.5 w-3.5" /> : <Save className="h-3.5 w-3.5" />}
              {notesStatus === "saved" ? "Done" : "Done"}
            </button>
          </div>
        </div>
        <textarea
          id="calculation-notes"
          value={notes}
          onChange={(event) => updateNotes(event.target.value)}
          placeholder="Add a note for this calculation..."
          rows={3}
          maxLength={500}
          className="w-full resize-y rounded-xl border border-input bg-background px-3 py-2 text-sm text-foreground outline-none transition-all duration-200 placeholder:text-muted-foreground focus:-translate-y-0.5 focus:border-primary focus:shadow-lg focus:shadow-primary/10 focus:ring-2 focus:ring-primary/30"
        />
        <div className="mt-2 flex flex-wrap items-center justify-between gap-2">
          <p
            key={notesStatus}
            className={`text-xs transition-colors duration-200 ${
              notesStatus === "error"
                ? "text-destructive"
                : notesStatus === "saved" || notesStatus === "restored"
                  ? "text-emerald-600 dark:text-emerald-400"
                  : "text-muted-foreground"
            }`}
            aria-live="polite"
          >
            {notesStatusText[notesStatus]}
          </p>
          <span className="text-xs text-muted-foreground">{notes.length}/500</span>
        </div>
      </section>

      {history.length > 0 ? (
        <section
          className="rounded-2xl border border-border bg-card p-4 shadow-sm animate-in fade-in-0 slide-in-from-bottom-2 duration-200"
          aria-labelledby="recent-calculations-heading"
        >
          <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
            <h2 id="recent-calculations-heading" className="flex items-center gap-2 text-sm font-bold text-foreground">
              <Clock3 className="h-4 w-4 text-primary" />
              Recent Calculations
            </h2>
            <div className="flex flex-wrap items-center gap-2">
              <button
                type="button"
                onClick={toggleAllHistorySelection}
                className="inline-flex items-center gap-1.5 rounded-full border border-border px-3 py-1.5 text-xs font-semibold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-primary/40 hover:bg-primary/5 hover:text-primary active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-primary/20"
              >
                {selectedHistoryIds.length === history.length ? "Unselect All" : "Select All"}
              </button>
              {selectedHistoryIds.length > 0 && (
                <button
                  type="button"
                  onClick={deleteSelectedHistory}
                  className="group inline-flex items-center gap-1.5 rounded-full border border-destructive/30 bg-destructive/5 px-3 py-1.5 text-xs font-semibold text-destructive transition-all duration-200 hover:-translate-y-0.5 hover:bg-destructive/10 active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
                >
                  <Trash2 className="h-3.5 w-3.5 transition-transform duration-200 group-hover:scale-110" />
                  Delete Selected ({selectedHistoryIds.length})
                </button>
              )}
              <button
                type="button"
                onClick={clearHistory}
                className="group inline-flex items-center gap-1.5 rounded-full border border-border px-3 py-1.5 text-xs font-semibold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
              >
                <Trash2 className="h-3.5 w-3.5 transition-transform duration-200 group-hover:scale-110" />
                Clear All
              </button>
            </div>
          </div>

          <div className="space-y-2">
            {history.map((item) => {
              const isEditing = editingHistoryId === item.id;
              return (
              <article
                key={item.id}
                className={`rounded-xl border p-3 transition-all duration-200 ${
                  selectedHistoryIds.includes(item.id)
                    ? "border-primary/50 bg-primary/5 shadow-md shadow-primary/10"
                    : "border-border/70 bg-background/60 hover:border-primary/25 hover:bg-accent/30"
                }`}
              >
                <div className="mb-2 flex items-start justify-between gap-3">
                  <label className="flex min-w-0 cursor-pointer items-center gap-2">
                    <input
                      type="checkbox"
                      checked={selectedHistoryIds.includes(item.id)}
                      onChange={() => toggleHistorySelection(item.id)}
                      className="h-4 w-4 rounded border-border text-primary accent-primary"
                      aria-label={`Select calculation from ${formatHistoryDate(item.timestamp)}`}
                    />
                    <time className="block truncate text-[11px] font-semibold uppercase tracking-wide text-muted-foreground" dateTime={new Date(item.timestamp).toISOString()}>
                      {formatHistoryDate(item.timestamp)}
                    </time>
                  </label>
                  <button
                    type="button"
                    onClick={() => deleteHistoryItem(item.id)}
                    className="group inline-flex shrink-0 items-center gap-1 rounded-full border border-border px-2.5 py-1 text-[11px] font-bold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
                    aria-label={`Delete calculation from ${formatHistoryDate(item.timestamp)}`}
                  >
                    <Trash2 className="h-3 w-3 transition-transform duration-200 group-hover:scale-110" />
                    Delete
                  </button>
                </div>
                {isEditing ? (
                  <div className="space-y-3 animate-in fade-in-0 slide-in-from-top-1 duration-150">
                    <label className="block text-xs font-bold text-foreground">
                      Inputs
                      <textarea
                        value={editingInputs}
                        onChange={(event) => setEditingInputs(event.target.value)}
                        rows={3}
                        className="mt-1 w-full resize-y rounded-xl border border-input bg-background px-3 py-2 text-xs font-medium text-foreground outline-none transition-all duration-200 focus:border-primary focus:ring-2 focus:ring-primary/25"
                      />
                    </label>
                    <label className="block text-xs font-bold text-foreground">
                      Result
                      <input
                        value={editingResult}
                        onChange={(event) => setEditingResult(event.target.value)}
                        className="mt-1 w-full rounded-xl border border-input bg-background px-3 py-2 text-sm font-bold text-foreground outline-none transition-all duration-200 focus:border-primary focus:ring-2 focus:ring-primary/25"
                      />
                    </label>
                    <label className="block text-xs font-bold text-foreground">
                      Notes
                      <textarea
                        value={editingNotes}
                        onChange={(event) => setEditingNotes(event.target.value)}
                        rows={2}
                        maxLength={500}
                        placeholder="Add or edit a note for this saved calculation..."
                        className="mt-1 w-full resize-y rounded-xl border border-input bg-background px-3 py-2 text-xs text-foreground outline-none transition-all duration-200 placeholder:text-muted-foreground focus:border-primary focus:ring-2 focus:ring-primary/25"
                      />
                    </label>
                    <div className="flex flex-wrap items-center gap-2">
                      <button
                        type="button"
                        onClick={saveEditingHistory}
                        className="inline-flex items-center gap-1.5 rounded-full bg-primary px-3 py-1.5 text-xs font-bold text-primary-foreground shadow-sm shadow-primary/20 transition-all duration-200 hover:-translate-y-0.5 hover:shadow-md hover:shadow-primary/25 active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-primary/30"
                      >
                        <Save className="h-3.5 w-3.5" />
                        Save Changes
                      </button>
                      <button
                        type="button"
                        onClick={() => removeHistoryNote(item.id)}
                        className="rounded-full border border-border px-3 py-1.5 text-xs font-semibold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
                      >
                        Remove Note
                      </button>
                      <button
                        type="button"
                        onClick={cancelEditingHistory}
                        className="rounded-full border border-border px-3 py-1.5 text-xs font-semibold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-primary/40 hover:bg-primary/5 hover:text-primary active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-primary/20"
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <p className="text-xs leading-relaxed text-muted-foreground">
                      <span className="font-semibold text-foreground">Inputs:</span> {item.inputs.join(", ")}
                    </p>
                    <p className="mt-1 text-sm font-bold leading-relaxed text-foreground">
                      <span className="text-primary">Result:</span> {item.result}
                    </p>
                    {item.notes && (
                      <p className="mt-1 text-xs leading-relaxed text-muted-foreground">
                        <span className="font-semibold text-foreground">Notes:</span> {item.notes}
                      </p>
                    )}
                    <div className="mt-3 flex flex-wrap items-center gap-2">
                      <button
                        type="button"
                        onClick={() => startEditingHistory(item)}
                        className="group inline-flex items-center gap-1.5 rounded-full border border-border px-3 py-1.5 text-[11px] font-bold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-primary/40 hover:bg-primary/5 hover:text-primary active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-primary/20"
                      >
                        <Pencil className="h-3 w-3 transition-transform duration-200 group-hover:scale-110" />
                        Edit
                      </button>
                      {item.notes && (
                        <button
                          type="button"
                          onClick={() => removeHistoryNote(item.id)}
                          className="rounded-full border border-border px-3 py-1.5 text-[11px] font-bold text-muted-foreground transition-all duration-200 hover:-translate-y-0.5 hover:border-destructive/40 hover:bg-destructive/5 hover:text-destructive active:translate-y-0 focus:outline-none focus:ring-2 focus:ring-destructive/20"
                        >
                          Remove Note
                        </button>
                      )}
                    </div>
                  </>
                )}
              </article>
            )})}
          </div>
        </section>
      ) : historyCleared ? (
          <section
            className="rounded-2xl border border-emerald-200 bg-emerald-50/70 p-4 shadow-sm dark:border-emerald-900/50 dark:bg-emerald-950/20"
            aria-live="polite"
          >
            <div className="flex items-center gap-3">
              <span
                className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-emerald-500 text-white shadow-lg shadow-emerald-500/25"
              >
                <Check className="h-5 w-5" />
              </span>
              <div>
                <p className="text-sm font-bold text-emerald-900 dark:text-emerald-100">Calculation history cleared</p>
                <p className="text-xs leading-relaxed text-emerald-700 dark:text-emerald-300">Your current inputs will stay clear until you change a calculator value again.</p>
              </div>
            </div>
          </section>
      ) : null}
    </div>
  );
}


